// AUTO-GENERATED — provides runtime access to static video data
// Videos are stored as a static JSON file (static/data/videos.json) to avoid
// bloating the JavaScript bundle. They are fetched on demand in the browser.

import { STATIC_VIDEO_CATEGORIES } from './video-categories';

export type VideoItem = {
  id: number;
  t: string;   // title
  v: string;   // YouTube videoId
  c: number;   // cateid
  h: 0 | 1;   // isHot
  d: string;   // date (dd/mm/yyyy)
};

export type VideoItemFull = {
  id: string;
  title: string;
  videoId: string;
  embedUrl: string;
  cateid: number;
  category: string;
  isHot: boolean;
  date: string;
};

let _videoCache: VideoItem[] | null = null;

/** Fetches all videos from the static JSON data file. Cached after first fetch. */
export async function fetchAllVideos(): Promise<VideoItem[]> {
  if (_videoCache) return _videoCache;
  const res = await fetch('/data/videos.json');
  if (!res.ok) throw new Error('Failed to load video data');
  _videoCache = await res.json();
  return _videoCache!;
}

/** Get videos for a specific category */
export async function fetchVideosByCategory(cateid: number): Promise<VideoItemFull[]> {
  const all = await fetchAllVideos();
  const catName = STATIC_VIDEO_CATEGORIES.find(c => c.cateid === cateid)?.name || '';
  return all
    .filter(v => v.c === cateid)
    .map(v => ({
      id: 'video-' + v.id,
      title: v.t,
      videoId: v.v,
      embedUrl: `https://www.youtube.com/embed/${v.v}`,
      cateid: v.c,
      category: catName,
      isHot: v.h === 1,
      date: v.d
    }));
}

/** Get hot/featured videos */
export async function fetchHotVideos(limit = 20): Promise<VideoItemFull[]> {
  const all = await fetchAllVideos();
  const catCache: Record<number, string> = {};
  STATIC_VIDEO_CATEGORIES.forEach(c => { catCache[c.cateid] = c.name; });
  return all
    .filter(v => v.h === 1)
    .slice(0, limit)
    .map(v => ({
      id: 'video-' + v.id,
      title: v.t,
      videoId: v.v,
      embedUrl: `https://www.youtube.com/embed/${v.v}`,
      cateid: v.c,
      category: catCache[v.c] || '',
      isHot: true,
      date: v.d
    }));
}

export { STATIC_VIDEO_CATEGORIES };
