import React, { useState, useEffect } from 'react';
import { Link } from 'gatsby';
import Header from '../components/header/header';
import Footer from '../components/Footer/Footer';
import { ResolvedContentProvider } from '../ppm/util/ResolvedContentContext';
import { fetchAllVideos, VideoItem } from '../contexts/db/video-loader';
import '../global.css';

const VideosPage = () => {
  const [videos, setVideos] = useState<VideoItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [visibleCount, setVisibleCount] = useState(24);
  const [activeCategory, setActiveCategory] = useState<string | null>(null); // Kept for type safety if used elsewhere, but not in filter

  useEffect(() => {
    const loadVideos = async () => {
      const data = await fetchAllVideos();
      setVideos(data);
      setLoading(false);
    };
    loadVideos();
  }, []);

  // Handle hash navigation
  useEffect(() => {
    const handleHash = () => {
      const hash = window.location.hash;
      if (hash) {
        const mapping: {[key:string]: string} = {
          '#phap-hoi': 'Pháp Hội',
          '#khoa-tu': 'Khóa Tu',
          '#kinh-trung-a-ham': 'Kinh Trung A Hàm',
          '#kinh-dien': 'Kinh Điển'
        };
        const searchVal = mapping[hash.toLowerCase()] || decodeURIComponent(hash.substring(1)).replace(/[\-–—]/g, ' ');
        
        if (searchVal) {
          setSearchTerm(searchVal);
          // Scroll to grid
          const container = document.querySelector('.media-grid');
          if (container) container.scrollIntoView({ behavior: 'smooth', block: 'start' });
        }
      }
    };

    handleHash();
    window.addEventListener('hashchange', handleHash);
    return () => window.removeEventListener('hashchange', handleHash);
  }, [loading]); // Re-run when videos are loaded to ensure scroll target exists

  // Reset visible count when searching or changing category
  useEffect(() => {
    setVisibleCount(24);
  }, [searchTerm, activeCategory]);

  const normalizeText = (text: string) => {
    return text.normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')
      .replace(/đ/g, 'd')
      .replace(/Đ/g, 'd')
      .toLowerCase()
      .trim();
  };

  const filteredVideos = React.useMemo(() => {
    if (!searchTerm) return videos;

    const catMapping: { [key: number]: string } = {};
    const { STATIC_VIDEO_CATEGORIES } = require('../contexts/db/video-categories');
    STATIC_VIDEO_CATEGORIES.forEach((c: any) => { catMapping[c.cateid] = c.name; });

    const q = normalizeText(searchTerm);

    return videos.filter(v => {
      const title = v && v.t ? normalizeText(String(v.t)) : '';
      const date = v && (v as any).d ? normalizeText(String((v as any).d)) : '';
      const catName = v && v.c ? normalizeText(catMapping[v.c] || '') : '';
      
      return title.includes(q) || date.includes(q) || catName.includes(q);
    });
  }, [videos, searchTerm]);

  const displayedVideos = filteredVideos.slice(0, visibleCount);

  return (
    <ResolvedContentProvider>
      <div className="media-page">
        <Header />
        <div style={{ height: '120px' }} /> {/* SPACING FOR FIXED HEADER */}

        <main className="media-container">
          <header className="media-header">
            <h1>Thư viện Video</h1>
            <div className="search-bar">
              <input
                type="text"
                placeholder="Tìm kiếm video..."
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
          </header>

          {loading ? (
            <div className="loading">Đang tải video...</div>
          ) : (
            <>
              <div className="media-grid">
                {displayedVideos.map((video: any) => (
                  <Link 
                    key={video.id} 
                    to={video.slug ? `/video/${video.slug}` : `/video/video-${video.id}`}
                    className="media-card"
                  >
                    <div className="media-thumb">
                      {video.v ? (
                        <img
                          src={`https://img.youtube.com/vi/${video.v}/mqdefault.jpg`}
                          alt={String(video.t)}
                        />
                      ) : (
                        <div className="placeholder-thumb" />
                      )}
                      <div className="play-overlay">
                        <span>▶</span>
                      </div>
                    </div>
                    <div className="media-info">
                      <h3>{String(video.t)}</h3>
                    </div>
                  </Link>
                ))}
              </div>

              {visibleCount < filteredVideos.length && (
                <div className="load-more-container">
                  <button
                    className="load-more-btn"
                    onClick={() => setVisibleCount(prev => prev + 24)}
                  >
                    Xem thêm video
                  </button>
                </div>
              )}
            </>
          )}
        </main>



        <Footer />

        <style dangerouslySetInnerHTML={{
          __html: `
          .media-page {
            background-color: #f5f3ee;
            min-height: 100vh;
          }
          .media-container {
            max-width: 1200px;
            margin: 0 auto;
            padding: 40px 20px;
          }
          .media-header {
            margin-bottom: 40px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            border-bottom: 2px solid #E6B422;
            padding-bottom: 20px;
          }
          .media-header h1 {
            font-family: 'Playfair Display', serif;
            color: #1a1a1a;
            margin: 0;
          }
          .search-bar input {
            padding: 10px 20px;
            border: 1px solid #ddd;
            border-radius: 25px;
            width: 300px;
            font-family: 'Inter', sans-serif;
          }
          .media-grid {
            display: grid;
            grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
            gap: 30px;
          }
          .media-card {
            background: white;
            border-radius: 12px;
            overflow: hidden;
            box-shadow: 0 4px 15px rgba(0,0,0,0.05);
            transition: transform 0.3s ease;
          }
          .media-card:hover {
            transform: translateY(-5px);
          }
          .media-thumb {
            position: relative;
            aspect-ratio: 16/9;
            background: #000;
          }
          .media-thumb img {
            width: 100%;
            height: 100%;
            object-fit: cover;
          }
          .play-overlay {
            position: absolute;
            top: 0; left: 0; width: 100%; height: 100%;
            background: rgba(0,0,0,0.3);
            display: flex;
            align-items: center;
            justify-content: center;
            opacity: 0;
            transition: opacity 0.3s ease;
            text-decoration: none;
          }
          .media-card:hover .play-overlay {
            opacity: 1;
          }
          .play-overlay span {
            color: white;
            font-size: 40px;
            background: rgba(230, 180, 34, 0.8);
            width: 60px;
            height: 60px;
            border-radius: 50%;
            display: flex;
            align-items: center;
            justify-content: center;
          }
          .media-info {
            padding: 15px;
          }
          .media-info h3 {
            margin: 0 0 5px 0;
            font-size: 16px;
            color: #1a1a1a;
            height: 40px;
            overflow: hidden;
            display: -webkit-box;
            -webkit-line-clamp: 2;
            -webkit-box-orient: vertical;
          }
          .media-info p {
            margin: 0;
            font-size: 12px;
            color: #E6B422;
            font-weight: 600;
            text-transform: uppercase;
          }
          @media (max-width: 768px) {
            .media-header { flex-direction: column; align-items: flex-start; gap: 20px; }
            .search-bar input { width: 100%; }
          }
          .load-more-container {
            display: flex;
            justify-content: center;
            margin-top: 50px;
            padding-bottom: 20px;
          }
          .load-more-btn {
            background-color: #E6B422;
            color: white;
            border: none;
            padding: 14px 40px;
            border-radius: 30px;
            font-size: 16px;
            font-weight: 600;
            font-family: 'Inter', sans-serif;
            cursor: pointer;
            transition: all 0.3s ease;
            box-shadow: 0 4px 15px rgba(230, 180, 34, 0.3);
          }
          .load-more-btn:hover {
            background-color: #d4a31d;
            transform: translateY(-2px);
            box-shadow: 0 6px 20px rgba(230, 180, 34, 0.4);
          }
        `}} />

      </div>
    </ResolvedContentProvider>
  );
};

export default VideosPage;
